// Measures the installed bundle size of `import { GridLayout }` for each shipped
// binding (@snapgridjs/react, @snapgridjs/svelte) and writes the numbers to a
// generated module so the hero + docs read ONE source of truth (no hand-maintained
// figures to drift). Decomposes snapgrid vs dnd-kit by bundling twice — once with
// dnd-kit included, once with it external. The framework runtime (react / svelte) is
// external in both, since the host app already ships it.
//
//   node apps/docs/scripts/measure-bundle.mjs
//
// Runs in `prebuild` (needs the workspace packages built + node_modules present).
// On any failure it leaves the committed bundle-size.ts untouched, so a measurement
// hiccup never breaks the build.
import { readFileSync } from "node:fs";
import { writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { brotliCompressSync } from "node:zlib";
import esbuild from "esbuild";
import { compile } from "svelte/compiler";

const RESOLVE_DIR = fileURLToPath(new URL("..", import.meta.url)); // apps/docs
const OUT = fileURLToPath(new URL("../components/generated/bundle-size.ts", import.meta.url));

// esbuild can't load `.svelte` on its own; the Svelte binding ships raw components, so
// compile them with svelte/compiler (client, runes) — `svelte` itself stays external so
// only snapgrid's own code (not the runtime the app already ships) is counted.
const sveltePlugin = {
  name: "svelte",
  setup(build) {
    build.onLoad({ filter: /\.svelte$/ }, (args) => {
      const { js } = compile(readFileSync(args.path, "utf8"), {
        generate: "client",
        css: "injected",
        filename: args.path,
      });
      return { contents: js.code, loader: "js", resolveDir: args.path.replace(/[^/]+$/, "") };
    });
  },
};

async function bundleBytes(pkg, { external, plugins = [], conditions }) {
  const result = await esbuild.build({
    stdin: {
      contents: `import { GridLayout } from "${pkg}"; if (GridLayout) globalThis.x = 1;`,
      resolveDir: RESOLVE_DIR,
      loader: "js",
    },
    bundle: true,
    minify: true,
    format: "esm",
    write: false,
    external,
    plugins,
    ...(conditions ? { conditions } : {}),
    logLevel: "silent",
  });
  return result.outputFiles[0].contents;
}

const kb = (bytes) => Math.round(brotliCompressSync(bytes).length / 1024);

// Total (framework external) vs own-only (dnd-kit external too) → the dnd-kit share.
async function measure(pkg, opts) {
  const total = kb(await bundleBytes(pkg, opts));
  const own = kb(await bundleBytes(pkg, { ...opts, external: [...opts.external, "@dnd-kit/*"] }));
  return { total, snapgrid: own, dndkit: total - own };
}

const emit = ({ total, snapgrid, dndkit }) =>
  `{\n  total: ${total},\n  snapgrid: ${snapgrid},\n  dndkit: ${dndkit},\n  unit: "kB",\n  compression: "brotli",\n} as const`;

try {
  // React is a peer the host app already ships, so exclude it.
  const react = await measure("@snapgridjs/react", { external: ["react", "react-dom"] });
  // Same for Svelte (external), with the compile plugin + Svelte export condition.
  const svelte = await measure("@snapgridjs/svelte", {
    external: ["svelte", "svelte/*"],
    plugins: [sveltePlugin],
    conditions: ["svelte", "browser", "import"],
  });

  await writeFile(
    OUT,
    `// AUTO-GENERATED by scripts/measure-bundle.mjs — do not edit by hand.
// Regenerate with: pnpm --filter @snapgridjs/docs measure
// Minified + tree-shaken \`import { GridLayout }\`, brotli, framework runtime excluded.
export const BUNDLE_SIZE = ${emit(react)};
export const BUNDLE_SIZE_SVELTE = ${emit(svelte)};
`,
  );
  console.log(
    `measured bundle → ${OUT}\n  react:  total ${react.total}kB = snapgrid ${react.snapgrid} + dnd-kit ${react.dndkit}\n  svelte: total ${svelte.total}kB = snapgrid ${svelte.snapgrid} + dnd-kit ${svelte.dndkit}  (brotli)`,
  );
} catch (err) {
  console.warn(`measure-bundle: skipped (${err.message}); keeping committed bundle-size.ts`);
}
